module RefModule (
    input clk,
    input [7:0] a,
    input [7:0] b,
    output reg [15:0] result
);
    reg [15:0] obf_mul_result; // Intermediate result of multiplication

    always @(posedge clk) begin
        // First stage: multiply the inputs
        obf_mul_result <= a * b;
    end

    always @(posedge clk) begin
        // Second stage: add constant
        result <= obf_mul_result + 5;
    end
endmodule
